--Fee a nivel de cuenta, no cliente

--Agregamos fee a tabla de cuenta
ALTER TABLE clientes.cuenta ADD column fee NUMERIC(45,20) DEFAULT NULL;
--Actualizamos desde tabla de clientes el Fee
update clientes.cuenta cta set fee =(select fee from clientes.cliente where id=cta.id_cliente);
--Borramos defaul de fee
ALTER TABLE clientes.cuenta ALTER COLUMN fee DROP DEFAULT;
--Marcamos como not null
ALTER TABLE clientes.cuenta ALTER COLUMN fee SET NOT NULL;

--Cambiar mapeo de maestros para usar nueva columna fee de cuenta y no cliente
--Vista de diferencias Fee
--Pre Cambios
SELECT * FROM public.vw_reporte_diferencias_fee;
--Modificamos vista
create or replace view public.vw_reporte_diferencias_fee
as
SELECT ie_neto.client_id,
       tb_cte.nombre,
       ie_neto.custodian,
       ie_neto.account_no,
       ie_neto.ingreso_egreso_efectivo,
       seg_fee.id                                                        AS id_segmento,
       seg_fee.glosa,
       seg_fee.monto_min,
       seg_fee.monto_max,
       seg_fee.annual_fee * 100::numeric                                 AS fee_seg,
       tb_cta.fee                                                        AS fee_cte,
       COALESCE((seg_fee.annual_fee * 100::numeric) = tb_cta.fee, false) AS flag_fee,
       CASE
           WHEN vw_sld.client_id IS NOT NULL THEN true
           ELSE false
           END                                                           AS flag_tiene_saldo
FROM (SELECT vw_ie.client_id,
             vw_ie.custodian,
             vw_ie.account_no,
             sum(vw_ie.usde_net_amount) AS ingreso_egreso_efectivo
      FROM vw_ingresos_egresos_diarios vw_ie
      WHERE vw_ie.ingreso_egreso = true
      GROUP BY vw_ie.client_id, vw_ie.custodian, vw_ie.account_no) ie_neto
         JOIN clientes.par_fee_segmento seg_fee ON ie_neto.ingreso_egreso_efectivo >= seg_fee.monto_min AND
                                                   ie_neto.ingreso_egreso_efectivo < seg_fee.monto_max
         JOIN clientes.cliente tb_cte ON ie_neto.client_id::text = tb_cte.identificador::text
    INNER JOIN clientes.cuenta tb_cta ON tb_cte.id= tb_cta.id_cliente AND ie_neto.account_no=tb_cta.id_cuenta_custodio
         LEFT JOIN fn_clientes_con_saldo(NULL::character varying) vw_sld(client_id, custodian, account_no)
                   ON ie_neto.client_id::text = vw_sld.client_id::text AND
                      ie_neto.custodian::text = vw_sld.custodian::text AND
                      ie_neto.account_no::text = vw_sld.account_no::text;


--Post Cambios
SELECT * FROM public.vw_reporte_diferencias_fee;


--Pre Cambio
SELECT * FROM clientes.vw_maestro_clientes_cuentas;
--Modificamos vista
create or replace view clientes.vw_maestro_clientes_cuentas
as
SELECT c.id                    AS id_interno_cliente,
       c.identificador         AS identificador_cliente,
       c.nombre                AS nombre_cliente,
       c.id_tipo_identificador AS id_tipo_identificador_cliente,
       ti.tipo_identificador   AS tipo_identificador_cliente,
       ti.glosa_identificador  AS glosa_identificador_cliente,
       cu.id                   AS id_interno_cuenta,
       cu.id_custodio,
       cu.id_cuenta_custodio,
       cu.habilitado,
       cu.fee
FROM clientes.cliente c
         JOIN clientes.tipo_identificador ti ON c.id_tipo_identificador = ti.id
         LEFT JOIN clientes.cuenta cu ON c.id = cu.id_cliente;


--Post Cambio
SELECT * FROM clientes.vw_maestro_clientes_cuentas;


--TODO: Verificar si esta corresponde, ya que es maestro de cliente, no cuenta
--Pre Cambio
SELECT * FROM clientes.vw_maestro_clientes;
--Modificamos vista
drop view clientes.vw_maestro_clientes;

create or replace view clientes.vw_maestro_clientes
as
SELECT cte.id,
       cte.identificador,
       cte.nombre,
       cte.id_tipo_identificador,
       tid.tipo_identificador,
       tid.glosa_identificador,
       tid.habilitado,
       (((SELECT string_agg(cta.id_cuenta_custodio::text, ','::text) AS string_agg
          FROM clientes.cuenta cta
          WHERE cta.id_cliente = cte.id)))::character varying(100) AS lista_cuentas
FROM clientes.cliente cte
         LEFT JOIN clientes.tipo_identificador tid ON cte.id_tipo_identificador = tid.id;


--Post Cambio
SELECT * FROM clientes.vw_maestro_clientes;

--Borramos columna
ALTER TABLE clientes.cliente DROP COLUMN fee;



